generated_oml:
// C3: Physical sensing components
instance MotorEncoder : DTDFVocab:SensingComponent [
    base:desc "Motor-mounted position encoder providing high‑resolution angle measurements for the motor shaft"
    DTDFVocab:producedData DataTransmittedMotorEncoder
]

instance GearboxEncoder : DTDFVocab:SensingComponent [
    base:desc "Secondary encoder located behind the gearbox delivering output shaft angle measurements"
    DTDFVocab:producedData DataTransmittedGearboxEncoder
]

instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Current sensor measuring motor phase current (I_M) supplied by the Siemens SINUMERIK 840D controller"
    DTDFVocab:producedData DataTransmittedMotorCurrent
]

// C4: Physical-to-virtual interaction
instance DataTransmittedMotorEncoder : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorEncoder
]

instance DataTransmittedGearboxEncoder : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxEncoder
]

instance DataTransmittedMotorCurrent : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

// C10: Data
instance TorqueTrace : DTDFVocab:Data [
    base:desc "Time‑series of computed motor torque (τ) derived from current and angle measurements"
    DTDFVocab:fromData DataTransmittedMotorCurrent, DataTransmittedMotorEncoder, DataTransmittedGearboxEncoder
    DTDFVocab:inputTo DataProcessingEngine
]

instance AngularVelocityTrace : DTDFVocab:Data [
    base:desc "Time‑series of angular velocity (ω) computed from successive encoder angle samples"
    DTDFVocab:fromData DataTransmittedMotorEncoder, DataTransmittedGearboxEncoder
    DTDFVocab:inputTo DataProcessingEngine
]

instance AccelerationTrace : DTDFVocab:Data [
    base:desc "Time‑series of angular acceleration derived from angular velocity data"
    DTDFVocab:fromData DataTransmittedMotorEncoder, DataTransmittedGearboxEncoder
    DTDFVocab:inputTo DataProcessingEngine
]

// C11: Enablers
instance DataProcessingEngine : DTDFVocab:Enabler [
    base:desc "MATLAB data processing component that calculates torque, velocity and acceleration from raw sensor streams"
    DTDFVocab:enables FrictionIdentificationService, ParameterEstimationService
]

instance SimulationEngine : DTDFVocab:Enabler [
    base:desc "MATLAB Simulink executable simulation environment executing friction models (Coulomb‑Viscous, Stribeck, Dahl, LuGre)"
    DTDFVocab:enables FrictionIdentificationService, ModelRefinementService
]

instance MQTTBroker : DTDFVocab:Enabler [
    base:desc "MQTT broker that streams live sensor data from the robot controller to the digital shadow"
    DTDFVocab:enables RealTimeVisualizationService
]

instance DashboardEngine : DTDFVocab:Enabler [
    base:desc "Web‑based dashboard visualising measured and simulated data in real time"
    DTDFVocab:enables RealTimeVisualizationService
]

// C6: Services
instance FrictionIdentificationService : DTDFVocab:Service [
    base:desc "Continuous identification of static, kinetic and viscous friction parameters using sensor data and simulation models"
    DTDFVocab:provides FrictionParameterInsight
]

instance ParameterEstimationService : DTDFVocab:Service [
    base:desc "Parameter estimation for both white‑box and black‑box friction models"
    DTDFVocab:provides ParameterEstimationInsight
]

instance RealTimeVisualizationService : DTDFVocab:Service [
    base:desc "Real‑time visualization of measured torque/velocity traces and simulated model outputs on a dashboard"
    DTDFVocab:provides VisualizationInsight
]

instance ModelRefinementService : DTDFVocab:Service [
    base:desc "Generation of refined model parameters to improve robot motion‑control accuracy"
    DTDFVocab:provides ModelRefinementInsight, AdjustMotionControlAction
]

// C17: Insights / Actions
instance FrictionParameterInsight : DTDFVocab:Insight [
    base:desc "Extracted friction parameters (static, kinetic, viscous) that characterize joint behavior"
]

instance ParameterEstimationInsight : DTDFVocab:Insight [
    base:desc "Estimated parameters for selected friction model (e.g., Coulomb‑Viscous, LuGre) indicating model fit quality"
]

instance VisualizationInsight : DTDFVocab:Insight [
    base:desc "Live comparison of measured and simulated torque and velocity data facilitating operator awareness"
]

instance ModelRefinementInsight : DTDFVocab:Insight [
    base:desc "Improved model fidelity resulting from updated friction parameters, leading to reduced positioning error"
]

instance AdjustMotionControlAction : DTDFVocab:Action [
    base:desc "Automatic update of robot controller motion‑control algorithm with refined friction parameters"
    DTDFVocab:IsAutomatic true
]

// C10: Models / Data
instance SysMLMotorGearboxModel : DTDFVocab:Model [
    base:desc "SysML block definition and internal block diagram describing the motor, gearwheel gearbox and cycloidal gearbox"
    DTDFVocab:inputTo SimulationEngine
]

instance FrictionModelCoulombViscous : DTDFVocab:Model [
    base:desc "Simulink implementation of a Coulomb‑Viscous friction model"
    DTDFVocab:inputTo SimulationEngine
]

instance FrictionModelStribeck : DTDFVocab:Model [
    base:desc "Simulink implementation of a Stribeck friction model"
    DTDFVocab:inputTo SimulationEngine
]

instance FrictionModelDahl : DTDFVocab:Model [
    base:desc "Simulink implementation of a Dahl friction model"
    DTDFVocab:inputTo SimulationEngine
]

instance FrictionModelLuGre : DTDFVocab:Model [
    base:desc "Simulink implementation of a LuGre friction model"
    DTDFVocab:inputTo SimulationEngine
]

instance DataCalculationModel : DTDFVocab:Model [
    base:desc "MATLAB model that computes torque, angular velocity and acceleration from measured currents and angles"
    DTDFVocab:inputTo DataProcessingEngine
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "Data acquisition and model updating occur in real‑time during robot operation, enabling continuous (online) identification of friction characteristics."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "The digital shadow is realised as a purpose‑driven constellation consisting of a single Asset (the first axis), a set of DataTraces (measured current I_M, reference outputs r_M, r_G, r_out and simulated outputs ˆr_M, ˆr_G, ˆr_out), Processing components that execute the Simulink models, and metadata that links each trace to its source, all conforming to the Digital Shadow Reference Model."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Traceability is maintained by linking every DataPoint to the originating sensor, processing component and model, ensuring that simulated and measured data can be directly compared; the use of both white‑box analytical friction equations and black‑box data‑driven models enables validation of model fidelity against live measurements."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "The physical‑to‑virtual link is realised using the MQTT protocol for real‑time streaming of sensor data; the digital shadow consumes these MQTT topics to populate its data traces."
]
